arrayPipelines.data:
[
  {
    "$match": {
      "email_date": {
        "$gte": {{ Math.floor(new Date(start_date.selectedDate).getTime() / 1) }},
        "$lte": {{ Math.floor(new Date(end_date.selectedDate).getTime() / 1) }}
      },
      "recipients": {{ user_id.selectedOptionValue ? user_id.selectedOptionValue : { "$exists": true } }},
      "environment": {{ env_select.selectedOptionValue || {"$exists": true} }},
			"client_id": {{ client_id.selectedOptionValue || { "$exists": true } }}
    }
  },
  { "$sort": { "email_date": -1 } },
  {
    "$project": {
      "_id": 0,
      "Email Date": {
        "$cond": {
          "if": { "$gt": ["$email_date", 0] },
          "then": {
            "$dateToString": {
              "format": "%Y-%m-%d",
              "date": { "$toDate": "$email_date" }
            }
          },
          "else": "N/A"
        }
      },
      "Workflow ID": { "$ifNull": ["$workflow_id", "N/A"] },
      "Workflow Name": { "$ifNull": ["$workflow_name", "N/A"] },
      "Subject": { "$ifNull": ["$subject", "N/A"] },
      "Template Name": { "$ifNull": ["$template_name", "N/A"] },
      "Client ID": { "$ifNull": ["$client_id", "N/A"] },
      "Environment": { "$ifNull": ["$environment", "N/A"] },
      "Recipients": { "$size": { "$ifNull": ["$recipients", []] } },
      "Unique Opens": { "$size": { "$ifNull": ["$unique_open_emails", []] } },
      "Unique Clicks": { "$size": { "$ifNull": ["$unique_click_ids", []] } },
      "Delivered": { "$ifNull": ["$delivered_count", 0] },
      "Opens": { "$ifNull": ["$open_count", 0] },
      "Clicks": { "$ifNull": ["$click_count", 0] },
      "Bounces": { "$ifNull": ["$bounce_count", 0] },
      "Unsubscribes": { "$ifNull": ["$unsubscribe_count", 0] }
    }
  }
]

